def translate_html_safe(translator, html_text):
    # Very naive translation: split by tags, translate text, reassemble
    # For a robust solution, you'd use BeautifulSoup, but since these are simple standard strings:
    import re
    parts = re.split(r'(<[^>]+>)', html_text)
    translated_parts = []
    
    for part in parts:
        if part.startswith('<') and part.endswith('>'):
            translated_parts.append(part)
        elif part.strip():
            # translate the chunk
            try:
                translated = translator.translate(part)
                translated_parts.append(translated)
            except Exception as e:
                print(f"Error translating: {e}")
                translated_parts.append(part)
        else:
            translated_parts.append(part)
    return "".join(translated_parts)

result = {}
for post in data:
    post_slug = post["slug"]
    result[post_slug] = {}
    
    for field in ["title", "excerpt", "content"]:
        result[post_slug][field] = {"ro": post[field]}
        
        for lang in [l for l in locales if l != 'ro']:
            print(f"Translating {post_slug} - {field} -> {lang}...")
            try:
                # deep_translator uses language codes.
                # bn = bengali, ne = nepali, si = sinhala
                translator = GoogleTranslator(source='ro', target=lang)
                
                if field == "content":
                    translated = translate_html_safe(translator, post[field])
                else:
                    translated = translator.translate(post[field])
                
                result[post_slug][field][lang] = translated
            except Exception as e:
                print(f"Failed to translate to {lang}: {e}")
                result[post_slug][field][lang] = post[field]
            
            # small sleep to avoid rate limits
            time.sleep(0.5)

with open("translated_blogs.json", "w", encoding="utf-8") as f:
    json.dump(result, f, ensure_ascii=False, indent=2)

print("Translation completed successfully!")
